```typescript
import { freezeService } from '../services/freeze.service';
import { ApiResponse } from '../types';

export class FreezeController {
  /**
   * 冻结账户
   * POST /api/freeze/account
   */
  async freezeAccount(req: Request): Promise<ApiResponse> {
    const body = await req.json();
    const { userId, reason, duration } = body;

    if (!userId || !reason) {
      return { success: false, error: '缺少必要参数' };
    }

    return freezeService.freezeAccount(userId, reason, duration);
  }

  /**
   * 解冻账户
   * POST /api/freeze/unfreeze
   */
  async unfreezeAccount(req: Request): Promise<ApiResponse> {
    const body = await req.json();
    const { userId } = body;

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.unfreezeAccount(userId);
  }

  /**
   * 查询冻结状态
   * GET /api/freeze/status/:userId
   */
  async getFreezeStatus(req: Request): Promise<ApiResponse> {
    const url = new URL(req.url);
    const userId = url.pathname.split('/').pop();

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.getFreezeStatus(userId);
  }

  /**
   * 查询冻结记录
   * GET /api/freeze/records/:userId
   */
  async getFreezeRecords(req: Request): Promise<ApiResponse> {
    const url = new URL(req.url);
    const userId = url.pathname.split('/').pop();

    if (!userId) {
      return { success: false, error: '缺少用户ID' };
    }

    return freezeService.getFreezeRecords(userId);
  }
}

export const freezeController = new FreezeController();
```

